content:
sudo nano /etc/named.conf
# Changes in options block:
listen-on port 53 { 127.0.0.1; 192.168.15.1; };
allow-query { localhost; 192.168.15.0/24; };
# Forward zone (add before include lines):
zone "bmc.example" IN {
type master;
file "bmc.example.zone";
};
# Reverse zone (add before include lines):
zone "15.168.192.in-addr.arpa" IN {
type master;
file "bmc.example.reverse";
};
sudo named-checkconf

# Save as DiskSpace.ps1
Get-PSDrive -PSProvider FileSystem | Select-Object Name, Used, Free, @{Name="TotalGB";Expression={[math]::round($_.Used/1GB + $_.Free/1GB,2)}}
Quick view of free and used space on all drives.

# Install BIND
sudo dnf install -y bind bind-utils

# Main config file
sudo nano /etc/named.conf

# Key settings in named.conf:
# listen-on port 53 { 127.0.0.1; 192.168.5.1; };
# allow-query { localhost; 192.168.5.0/24; };
# recursion yes;

# Zone declarations to add in named.conf:
# zone "bmc.test" IN {
#     type master;
#     file "bmc.test.db";
# };
# zone "5.168.192.in-addr.arpa" IN {
#     type master;
#     file "192.168.5.db";
# };

# Zone file location: /var/named/

# Check named.conf syntax
sudo named-checkconf

# Start and enable BIND
sudo systemctl enable --now named
sudo systemctl status named

# Open firewall
sudo firewall-cmd --add-service=dns --permanent
sudo firewall-cmd --reload

# Test DNS
dig @192.168.5.1 rocky1.bmc.test
dig @192.168.5.1 bmc.test MX
nslookup rocky1.bmc.test 192.168.5.1
host rocky1.bmc.test
host -t MX bmc.test

ipconfig /all
Get-NetAdapter | Format-List -Property *
Get-WindowsFeature | Where-Object {$_.installed -match $True}

sudo dnf install -y bind bind-utils

sudo tee /etc/named.conf <<EOM
options {
 listen-on port 53 { 127.0.0.1; 192.168.5.1; };
 listen-on-v6 port 53 { ::1; };
 directory "/var/named";
 dump-file "/var/named/data/cache_dump.db";
 statistics-file "/var/named/data/named_stats.txt";
 memstatistics-file "/var/named/data/named_mem_stats.txt";
 secroots-file "/var/named/data/named.secroots";
 recursing-file "/var/named/data/named.recursing";
 allow-query { localhost; 172.16.0.0/22; 10.13.14.0/24; 192.168.5.0/24; };
 recursion yes;
 dnssec-enable yes;
 dnssec-validation yes;
 managed-keys-directory "/var/named/dynamic";
 pid-file "/run/named/named.pid";
 session-keyfile "/run/named/session.key";
 include "/etc/crypto-policies/back-ends/bind.config";
};
logging {
 channel default_debug {
  file "data/named.run";
  severity dynamic;
 };
};
zone "." IN {
 type hint;
 file "named.ca";
};
zone "bmc.test" IN {
 type master;
 file "bmc.test.db";
};
zone "5.168.192.in-addr.arpa" IN {
 type master;
 file "192.168.5.db";
};
include "/etc/named.rfc1912.zones";
include "/etc/named.root.key";
EOM

# Variables
$name = "school.test"
$ip = "172.16.1.1"
$servers = @("dc1", "srv1", "rras1")   # array
$cred = Get-Credential                   # prompt for credentials

# String operations
$name.ToUpper()
$name.Replace(".test", ".local")
"Server is: $name"                       # string interpolation
"IP: {0}, Name: {1}" -f $ip, $name      # format string

# Conditionals
if ($name -eq "school.test") {
    Write-Host "Correct domain"
} elseif ($name -eq "bmc.test") {
    Write-Host "BMC domain"
} else {
    Write-Host "Unknown domain"
}

# Comparison operators
# -eq   equal
# -ne   not equal
# -gt   greater than
# -lt   less than
# -like wildcard match (e.g. -like "Jan*")
# -match regex match
# -contains array contains value

# For loop
foreach ($server in $servers) {
    Write-Host "Pinging $server"
    Test-NetConnection $server
}

# For loop with range
1..10 | ForEach-Object { Write-Host "Number: $_" }

# While loop
$i = 0
while ($i -lt 5) {
    Write-Host $i
    $i++
}

# ForEach-Object in pipeline
$servers | ForEach-Object { Test-NetConnection $_ }
Get-ADUser -Filter * | ForEach-Object { Set-ADUser $_ -Description "Staff" }

# Try / Catch error handling
try {
    Get-ADUser nonexistentuser
} catch {
    Write-Host "Error: $_"
}
